from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_limiter import Limiter
from flask_mail import Mail, Message
import os
import uuid

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USERNAME'] = 'your-email@example.com'
app.config['MAIL_PASSWORD'] = 'your-email-password'
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USE_SSL'] = False

db = SQLAlchemy(app)
mail = Mail(app)
limiter = Limiter(app, key_func=lambda: request.remote_addr)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(120), unique=True, nullable=False)

db.create_all()

@app.route('/reset-password', methods=['POST'])
@limiter.limit("5 per hour")
def reset_password():
    email = request.json.get('email')
    if not email:
        return jsonify({"message": "If the email exists, a reset link will be sent."}), 200

    token = str(uuid.uuid4())
    reset_token = PasswordResetToken(email=email, token=token)
    db.session.add(reset_token)
    db.session.commit()

    reset_link = f"http://example.com/reset-password/{token}"
    msg = Message('Password Reset Request', sender='your-email@example.com', recipients=[email])
    msg.body = f"Please use the following link to reset your password: {reset_link}"
    mail.send(msg)

    return jsonify({"message": "If the email exists, a reset link will be sent."}), 200

if __name__ == '__main__':
    app.run(debug=True)